package com.example.demo.controller; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/student") public class StudentController{ @GetMapping("/") public String welcome(){ return "Welcome to Student API"; } @GetMapping("/details") public String details(){ return "Student Name: Rahul, Course: BCA"; } @PostMapping("/add") public String addStudent(@RequestBody String student){ return "Student Added: "+student; } } 